# ---------------------------------------------------------------------------
# Slack delivery
# ---------------------------------------------------------------------------

def post_to_slack(req: BriefingRequest, assessment: dict, pdf_bytes: bytes):
    company    = safe_str(req.company_name, "Unknown Company")
    lead       = safe_str(req.lead_name,    "Unknown Contact")
    motivation = assessment.get("motivation_hypothesis", "")
    strengths  = assessment.get("key_strengths", [])
    strengths_text = "\n".join(f"• {s}" for s in strengths)

    if SLACK_WEBHOOK_URL:
        blocks = [
            {
                "type": "header",
                "text": {"type": "plain_text", "text": f"Pre-Call Brief: {company}"}
            },
            {
                "type": "section",
                "fields": [
                    {"type": "mrkdwn", "text": f"*Contact*\n{lead}"},
                    {"type": "mrkdwn", "text": f"*Location*\n{extract_city_state(req.location or '')}"},
                    {"type": "mrkdwn", "text": f"*Founded*\n{safe_str(req.founded_year, 'Unknown')}"},
                    {"type": "mrkdwn", "text": f"*Website*\n{(req.website or '').replace('https://','').rstrip('/')}"},
                ]
            },
            {"type": "divider"},
            {
                "type": "section",
                "text": {"type": "mrkdwn", "text": f"*Exit Motivation*\n{motivation}"}
            },
            {
                "type": "section",
                "text": {"type": "mrkdwn", "text": f"*Deal Strengths*\n{strengths_text}"}
            },
            {"type": "divider"},
            {
                "type": "context",
                "elements": [{"type": "mrkdwn", "text": "_Generated by Gamic · Full PDF attached_"}]
            }
        ]
        requests.post(SLACK_WEBHOOK_URL, json={"blocks": blocks}, timeout=10)

    if SLACK_BOT_TOKEN and SLACK_CHANNEL_ID:
        company_safe = re.sub(r"[^a-zA-Z0-9_]", "_", company)
        filename     = f"Pre_Call_Brief_{company_safe}.pdf"

        r1 = requests.post(
            "https://slack.com/api/files.getUploadURLExternal",
            headers={"Authorization": f"Bearer {SLACK_BOT_TOKEN}"},
            json={"filename": filename, "length": len(pdf_bytes)},
            timeout=15,
        )
        data1      = r1.json()
        upload_url = data1.get("upload_url")
        file_id    = data1.get("file_id")

        if upload_url and file_id:
            requests.post(upload_url, data=pdf_bytes, timeout=30)
            requests.post(
                "https://slack.com/api/files.completeUploadExternal",
                headers={"Authorization": f"Bearer {SLACK_BOT_TOKEN}"},
                json={
                    "files":           [{"id": file_id, "title": f"Pre-Call Brief: {company}"}],
                    "channel_id":      SLACK_CHANNEL_ID,
                    "initial_comment": f"Full briefing PDF for {lead} at {company}",
                },
                timeout=15,
            )


# ---------------------------------------------------------------------------
# Endpoint
# ---------------------------------------------------------------------------

@app.post("/generate-briefing")
async def generate_briefing(req: BriefingRequest):
    if not req.company_name and not req.lead_name:
        raise HTTPException(status_code=422, detail="At least company_name or lead_name is required.")
    try:
        assessment   = generate_assessment(req)
        html_content = build_pdf_html(req, assessment)
        pdf_bytes    = WeasyHTML(string=html_content).write_pdf()
        post_to_slack(req, assessment, pdf_bytes)
        return {"status": "success", "company": req.company_name}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


@app.get("/health")
async def health():
    return {"status": "ok"}
